const email = $input.first().json;
const rawMessageId = email.messageId || (email.headers && (email.headers['message-id'] || email.headers['Message-ID'])) || email.id || '';
const rawInReplyTo = email.inReplyTo || (email.headers && (email.headers['in-reply-to'] || email.headers['In-Reply-To'])) || '';
const cleanId = (id) => (id || '').replace(/[<>\s]/g, '');
const messageId = cleanId(rawMessageId) || (email.id || '');
const inReplyTo = cleanId(rawInReplyTo);
// Usar threadId nativo de Gmail (más confiable que in-reply-to)
const threadId = email.threadId || inReplyTo || messageId;
return [{ json: { ...email, _headers: { messageId, inReplyTo, threadId, isReply: !!inReplyTo } } }];

const result = $input.first().json;
console.log(`Reply procesado: record_id=${result.record_id}, twenty_id=${result.twenty_tramite_id}`);
return [{ json: { ...result, accion: 'reply_procesado' } }];

const crypto = require('crypto');
const email = $('Gmail Trigger').first().json;
const headers_data = $('Extraer Headers Email').first().json;
const tramite_id = crypto.randomUUID();
const now = new Date();
// Formato TRM-YYYY-NNNNN alineado con FastAPI
const seqNum = String(Math.floor(Math.random() * 99998) + 1).padStart(5, '0');
const folio = `TRM-${now.getFullYear()}-${seqNum}`;
const remitente = email.from?.value?.[0]?.address || (typeof email.from === 'string' ? email.from : '') || '';
const nombre_remitente = email.from?.value?.[0]?.name || remitente;
const asunto = email.subject || '';
const cuerpo = email.text || email.snippet || '';
const fecha = email.date || now.toISOString();
const message_id = headers_data._headers?.messageId || email.id || '';
// Usar threadId nativo de Gmail
const thread_id = email.threadId || headers_data._headers?.threadId || message_id;
const tiene_adjuntos = (email.attachments || []).length > 0;
return [{ json: { tramite_id, folio, remitente, nombre_remitente, asunto, cuerpo, cuerpo_html: email.html || '', fecha, message_id, thread_id, tiene_adjuntos } }];

// Preparar datos del email + adjuntos en base64 para envío a FastAPI vía multipart/form-data
const email = $('Gmail Trigger').first().json;
const uuidData = $('Generar UUID Trámite').first().json;

// Obtener binarios de Gmail Trigger (adjuntos del correo)
let gmailBinary = {};
try {
  gmailBinary = $('Gmail Trigger').first().binary || {};
} catch(e) {
  gmailBinary = {};
}

const adjuntos = [];
for (const [key, binaryInfo] of Object.entries(gmailBinary)) {
  if (binaryInfo && key.startsWith('attachment_')) {
    let base64Data = '';
    try {
      base64Data = Buffer.isBuffer(binaryInfo.data)
        ? binaryInfo.data.toString('base64')
        : (typeof binaryInfo.data === 'string' ? binaryInfo.data : '');
    } catch(e) { base64Data = ''; }
    adjuntos.push({
      campo: key,
      nombre_archivo: binaryInfo.fileName || key,
      tipo_mime: binaryInfo.mimeType || 'application/octet-stream',
      tamano_bytes: binaryInfo.fileSize || 0,
      datos_base64: base64Data
    });
  }
}

const email_data = {
  tramite_id: uuidData.tramite_id,
  folio: uuidData.folio,
  remitente: uuidData.remitente,
  nombre_remitente: uuidData.nombre_remitente,
  asunto: uuidData.asunto,
  cuerpo: uuidData.cuerpo,
  cuerpo_html: uuidData.cuerpo_html || '',
  fecha: uuidData.fecha,
  message_id: uuidData.message_id,
  thread_id: uuidData.thread_id || email.threadId || '',
  tiene_adjuntos: adjuntos.length > 0,
  adjuntos_count: adjuntos.length,
  adjuntos
};

return [{ json: { email_data: JSON.stringify(email_data), _adjuntos_count: adjuntos.length } }];

const resp = $input.first().json;
const gen = $('Generar UUID Trámite').first().json;
const status = resp.statusCode || 200;
const body = resp.body || resp;
const error_detectado = status >= 400 || !!body.detail || !!body.error;
const error_message = error_detectado ? (body.detail || body.error || `HTTP ${status}`) : null;
return [{ json: {
  tramite_id: gen.tramite_id,
  folio: gen.folio,
  remitente: gen.remitente,
  nombre_remitente: gen.nombre_remitente,
  asunto: gen.asunto,
  cuerpo: gen.cuerpo,
  fecha: gen.fecha,
  message_id: gen.message_id,
  tiene_adjuntos: gen.tiene_adjuntos,
  error_detectado,
  error_message,
  confianza_global: body.confianza_global || 0,
  tipo_tramite: body.tipo_tramite || null,
  ramo: body.ramo || null,
  numero_poliza: body.numero_poliza || null,
  nombre_asegurado: body.nombre_asegurado || null,
  agente_cua: body.agente_cua || null,
  resumen: body.resumen || '',
  es_duplicado_posible: body.es_duplicado_posible || false,
  tramite_duplicado_ref: body.tramite_duplicado_ref || null
}}];

