const a4resp = $input.first().json;
const a3data = $('Evaluar Agente 3').first().json;
const status = a4resp.statusCode || 200;
const body = a4resp.body || a4resp;
const error_a4 = status >= 400 || !!body.detail;
const motivo = body.motivo_revision || body.detail || (error_a4 ? `HTTP ${status}` : null);
// Map API status to workflow resultado: 'completado' → 'creado' per spec
const resultado = error_a4 ? 'error' : (body.status === 'completado' ? 'creado' : (body.status || 'revision_manual'));
const folio = body.folio || a3data.folio;
const analista_asignado = body.analista?.nombre || 'Especialista asignado';
const twenty_tramite_id = body.twenty_tramite_id || null;
return [{ json: {
  tramite_id: a3data.tramite_id,
  folio,
  remitente: a3data.remitente,
  nombre_remitente: a3data.nombre_remitente,
  asunto: a3data.asunto,
  resultado,
  analista_asignado,
  twenty_tramite_id,
  motivo,
  ramo: a3data.ramo,
  tipo_tramite: a3data.tipo_tramite,
  error_a4,
  error_message_a4: error_a4 ? motivo : null
}}];

